import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";

import {
  Chart as ChartJS,
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Tooltip,
  Legend
} from "chart.js";

import { Line } from "react-chartjs-2";

ChartJS.register(
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Tooltip,
  Legend
);

const severityMap = { P0: 4, P1: 3, P2: 2, P3: 1 };

export default function IncidentDetail() {
  const { id } = useParams();

  const [trend, setTrend] = useState([]);

  useEffect(() => {
    fetch(`http://localhost:8000/incident/${id}/trend`)
      .then(res => res.json())
      .then(data => setTrend(data || []));
  }, [id]);

  // 🚨 IMPORTANT FIX: avoid null render crash
  if (!trend || trend.length === 0) {
    return (
      <div style={{ padding: "20px" }}>
        <h2>Incident #{id}</h2>
        <p>No trend data available</p>
      </div>
    );
  }

  const chartData = {
    labels: trend.map(t =>
      new Date(t.time).toLocaleTimeString()
    ),
    datasets: [
      {
        label: "Severity Trend",
        data: trend.map(t => severityMap[t.severity]),
        borderColor: "#2f6fed",
        tension: 0.3
      }
    ]
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Incident #{id}</h2>

      <Line data={chartData} />
    </div>
  );
}
